  # ----- helpers that wrap matched text in tags -----------------
  def bold_fmt(s: str) -> str:
      # Escape single quote, then wrap in <strong>
      return f'<strong>{s.replace("'", "'")}</strong>'

  def italic_fmt(s: str) -> str:
      # Escape single quote, then wrap in <em>
      return f'<em>{s.replace("'", "')}</em>'.replace("'", "'')

